__global__ void measure_dram_latency(volatile uint32_t* indices, uint64_t* cycles_out, size_t size) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t idx = 0;

    // Warm up the cache
    #pragma unroll 1
    for (uint64_t i = 0; i < 1000; i++) {
        idx = indices[idx];
    }

    // Compiler barrier before timing
    asm volatile("" : : : "memory");

    volatile uint64_t start = clock64();

    #pragma unroll 1
    for (uint64_t i = 0; i < 1000000; i++) {
        idx = indices[idx];
    }

    volatile uint64_t end = clock64();

    // Compiler barrier after timing
    asm volatile("" : : : "memory");

    // Anti-optimization: consume idx into 64-bit sink
    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    *cycles_out = (end - start) / 1000000;
}

int main() {
    const size_t ARRAY_SIZE = 32 * 1024 * 1024; // 32M elements = 128 MB
    const int NUM_TRIALS = 3;
    uint64_t trial_results[NUM_TRIALS];

    volatile uint32_t* d_indices;
    uint64_t* d_cycles;

    // Allocate device memory
    cudaMalloc((void**)&d_indices, ARRAY_SIZE * sizeof(uint32_t));
    cudaMalloc((void**)&d_cycles, sizeof(uint64_t));

    // Create random permutation on host
    uint32_t* h_indices = (uint32_t*)malloc(ARRAY_SIZE * sizeof(uint32_t));
    for (size_t i = 0; i < ARRAY_SIZE; i++) {
        h_indices[i] = (uint32_t)i;
    }

    // Fisher-Yates shuffle with LCG
    uint64_t seed = 123456789;
    for (size_t i = ARRAY_SIZE - 1; i > 0; i--) {
        seed = seed * 1664525 + 1013904223; // LCG
        size_t j = seed % (i + 1);
        uint32_t temp = h_indices[i];
        h_indices[i] = h_indices[j];
        h_indices[j] = temp;
    }

    // Copy to device
    cudaMemcpy((void*)d_indices, h_indices, ARRAY_SIZE * sizeof(uint32_t), cudaMemcpyHostToDevice);

    // Run trials
    for (int trial = 0; trial < NUM_TRIALS; trial++) {
        measure_dram_latency<<<1, 1>>>(d_indices, d_cycles, ARRAY_SIZE);
        cudaDeviceSynchronize();

        uint64_t h_cycles;
        cudaMemcpy(&h_cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
        trial_results[trial] = h_cycles;
    }

    // Sort to get median
    std::sort(trial_results, trial_results + NUM_TRIALS);
    uint64_t median_cycles = trial_results[NUM_TRIALS / 2];

    printf("dram_latency_cycles: %lu\n", (unsigned long)median_cycles);

    // Cleanup
    free(h_indices);
    cudaFree((void*)d_indices);
    cudaFree(d_cycles);

    return 0;
}

#include <cuda_runtime.h>
