__global__ void cache_sweep_kernel(volatile uint32_t* data, uint32_t stride, size_t num_accesses, uint64_t* elapsed_cycles) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    volatile uint64_t start = clock64();

    #pragma unroll 1
    for (size_t i = 0; i < num_accesses; i++) {
        uint32_t idx = (i * stride) % (num_accesses * stride);
        data[idx] = data[idx] + 1;
    }

    volatile uint64_t end = clock64();
    *elapsed_cycles = end - start;

    volatile uint64_t sink64 = (uint64_t)data[0];
    asm volatile("") : "+l"(sink64) : : "memory");
}

int main() {
    const size_t min_size_mb = 1;
    const size_t max_size_mb = 100;
    const size_t step_size_mb = 1;
    const size_t num_trials = 3;

    int device_id = 0;
    cudaGetDevice(&device_id);

    size_t* times_ns = (size_t*)malloc((max_size_mb - min_size_mb + 1) * sizeof(size_t));

    for (size_t size_mb = min_size_mb; size_mb <= max_size_mb; size_mb += step_size_mb) {
        size_t array_size = (size_mb * 1024 * 1024) / sizeof(uint32_t);

        volatile uint32_t* d_data;
        cudaMalloc((void**)&d_data, array_size * sizeof(uint32_t));
        cudaMemset((void*)d_data, 0, array_size * sizeof(uint32_t));

        uint32_t stride = 32; // 128 bytes to bypass L1 on Volta+
        size_t num_accesses = 100000; // Fixed number of accesses

        uint64_t* d_cycles;
        cudaMalloc((void**)&d_cycles, sizeof(uint64_t));

        cudaEvent_t start, stop;
        cudaEventCreate(&start);
        cudaEventCreate(&stop);

        cudaDeviceSynchronize();

        cudaEventRecord(start);
        cache_sweep_kernel<<<1, 1>>>(d_data, stride, num_accesses, d_cycles);
        cudaEventRecord(stop);
        cudaEventSynchronize(stop);

        float elapsed_ms = 0.0f;
        cudaEventElapsedTime(&elapsed_ms, start, stop);
        times_ns[size_mb - min_size_mb] = (size_t)(elapsed_ms * 1000000);

        cudaFree((void*)d_data);
        cudaFree(d_cycles);
        cudaEventDestroy(start);
        cudaEventDestroy(stop);
    }

    int* d_times_ns;
    cudaMalloc((void**)&d_times_ns, (max_size_mb - min_size_mb + 1) * sizeof(size_t));
    cudaMemcpy(d_times_ns, times_ns, (max_size_mb - min_size_mb + 1) * sizeof(size_t), cudaMemcpyHostToDevice);

    size_t l2_size_mb = 0;
    size_t min_time_ns = SIZE_MAX;

    for (size_t size_mb = min_size_mb; size_mb <= max_size_mb; size_mb += step_size_mb) {
        size_t time_ns = times_ns[size_mb - min_size_mb];

        if (size_mb <= 8) {
            if (time_ns < min_time_ns) {
                min_time_ns = time_ns;
            }
        } else {
            size_t baseline_ns = times_ns[7];
            double speedup = (double)baseline_ns / time_ns;

            if (speedup > 2.0 && l2_size_mb == 0) {
                l2_size_mb = size_mb - 1;
                break;
            }
        }
    }

    if (l2_size_mb == 0) {
        size_t min_time = SIZE_MAX;
        for (size_t size_mb = min_size_mb; size_mb <= max_size_mb; size_mb += step_size_mb) {
            if (times_ns[size_mb - min_size_mb] < min_time) {
                min_time = times_ns[size_mb - min_size_mb];
                l2_size_mb = size_mb;
            }
        }
    }

    printf("l2_cache_size_mb: %lu\n", (unsigned long)l2_size_mb);

    free(times_ns);
    cudaFree(d_times_ns);

    return 0;
}

