__global__ void measure_l2_cache_size(volatile uint32_t* array, volatile uint64_t* result, size_t array_size_bytes, size_t stride) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    size_t num_elements = array_size_bytes / sizeof(uint32_t);
    size_t idx = 0;

    asm volatile("" ::: "memory");
    volatile uint64_t start = clock64();
    #pragma unroll 1
    for (uint64_t i = 0; i < num_elements / stride; i++) {
        idx = array[idx];
        idx += stride;
        if (idx >= num_elements) idx = 0;
    }
    volatile uint64_t end = clock64();
    asm volatile("" ::: "memory");

    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");
    *result = end - start;
}

int main() {
    const size_t min_size = 1 * 1024 * 1024;   // 1 MB
    const size_t max_size = 128 * 1024 * 1024; // 128 MB
    const size_t step_size = 1 * 1024 * 1024;  // 1 MB steps

    uint32_t* d_array;
    volatile uint64_t* d_result;

    // Allocate maximum size needed
    cudaMalloc(&d_array, max_size);
    cudaMalloc(&d_result, sizeof(uint64_t));

    // Initialize array with sequential pattern
    size_t max_elements = max_size / sizeof(uint32_t);
    uint32_t* h_array = (uint32_t*)malloc(max_size);
    for (size_t i = 0; i < max_elements; i++) {
        h_array[i] = (i + 1) % max_elements;
    }
    cudaMemcpy(d_array, h_array, max_size, cudaMemcpyHostToDevice);

    const size_t stride = 32; // 128-byte stride to bypass L1
    const int num_trials = 10;

    uint64_t* latencies = (uint64_t*)malloc((max_size / step_size) * sizeof(uint64_t));

    for (size_t size = min_size; size <= max_size; size += step_size) {
        // Warmup run
        measure_l2_cache_size<<<1,1>>>(d_array, d_result, size, stride);
        cudaDeviceSynchronize();

        // Timed runs
        uint64_t total_cycles = 0;
        for (int trial = 0; trial < num_trials; trial++) {
            measure_l2_cache_size<<<1,1>>>(d_array, d_result, size, stride);
            cudaDeviceSynchronize();
            total_cycles += *d_result;
        }

        uint64_t avg_cycles = total_cycles / num_trials;
        latencies[size / step_size - 1] = avg_cycles;

        printf("size_%luMB: %lu\n", size / (1024*1024), avg_cycles);
    }

    // Find cache cliff (largest non-jumping value)
    // Look for first significant increase in latency
    uint64_t baseline = latencies[0];
    size_t cliff_idx = 0;
    for (size_t i = 1; i < (max_size / step_size); i++) {
        if (latencies[i] > baseline * 1.5 && latencies[i] > latencies[i-1] * 1.2) {
            cliff_idx = i;
            break;
        }
    }

    float l2_size_mb = (cliff_idx > 0) ? (cliff_idx * step_size / (1024.0f * 1024.0f)) : 0.0f;
    printf("l2_cache_size_mb: %.1f\n", l2_size_mb);

    free(h_array);
    free(latencies);
    cudaFree(d_array);
    cudaFree(d_result);

    return 0;
}

#include <cuda_runtime.h>
