__global__ void clock_measurement_kernel(volatile uint64_t* cycles) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    asm volatile("" : : : "memory");
    volatile uint64_t start = clock64();

    // Compute-intensive loop
    #pragma unroll 1
    for (uint64_t i = 0; i < 10000000; i++) {
        // Arithmetic operations
        float x = 1.0f;
        #pragma unroll 8
        for (int j = 0; j < 100; j++) {
            x = x * 1.0001f + 0.0001f;
        }
    }

    volatile uint64_t end = clock64();
    asm volatile("" : : : "memory");

    cycles[0] = end - start;
}

int main() {
    int device = 0;
    cudaSetDevice(device);

    cudaDeviceProp prop;
    cudaGetDeviceProperties(&prop, device);

    volatile uint64_t* d_cycles;
    cudaMalloc((void**)&d_cycles, sizeof(uint64_t));

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    uint64_t cycle_counts[3];
    float elapsed_times[3];

    // Run 3 trials
    for (int trial = 0; trial < 3; trial++) {
        // Warm up
        clock_measurement_kernel<<<1, 1>>>(d_cycles);
        cudaDeviceSynchronize();

        // Measure with cudaEvent
        cudaEventRecord(start);
        clock_measurement_kernel<<<1, 1>>>(d_cycles);
        cudaEventRecord(stop);
        cudaEventSynchronize(stop);

        float elapsed_ms = 0.0f;
        cudaEventElapsedTime(&elapsed_ms, start, stop);
        elapsed_times[trial] = elapsed_ms;

        uint64_t host_cycles;
        cudaMemcpy((void*)&host_cycles, (const void*)d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
        cycle_counts[trial] = host_cycles;
    }

    // Calculate frequencies
    float frequencies[3];
    for (int i = 0; i < 3; i++) {
        float elapsed_us = elapsed_times[i] * 1000.0f;
        frequencies[i] = (float)cycle_counts[i] / elapsed_us;
    }

    // Sort to find median
    std::sort(frequencies, frequencies + 3);
    float median_mhz = frequencies[1];

    printf("actual_boost_clock_mhz: %d\n", (int)median_mhz);

    cudaFree((void*)d_cycles);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void l2_cache_test_kernel(volatile uint32_t* data, size_t size, size_t stride, uint64_t* dummy) {
    size_t idx = threadIdx.x + blockIdx.x * blockDim.x;
    size_t total_elements = size / sizeof(uint32_t);

    // Each thread processes a portion of the array
    size_t elements_per_thread = total_elements / (gridDim.x * blockDim.x);
    size_t start_idx = idx * elements_per_thread;

    volatile uint32_t value = 0;
    for (size_t i = 0; i < elements_per_thread; i += stride / sizeof(uint32_t)) {
        value += data[(start_idx + i) % total_elements];
    }

    // Prevent optimization
    if (threadIdx.x == 0 && blockIdx.x == 0) {
        *dummy = value;
    }
}

int main() {
    const size_t MB = 1024 * 1024;
    const size_t min_size = 1 * MB;   // 1 MB
    const size_t max_size = 100 * MB; // 100 MB
    const size_t step_size = 1 * MB;  // 1 MB steps
    const size_t stride = 128;        // 128-byte stride
    const int repetitions = 10;

    volatile uint32_t* d_data;
    uint64_t* d_dummy;

    cudaMalloc(&d_data, max_size);
    cudaMalloc(&d_dummy, sizeof(uint64_t));

    float* times = (float*)malloc((max_size - min_size) / step_size * sizeof(float));

    // Warm up
    l2_cache_test_kernel<<<1, 1>>>(d_data, min_size, stride, d_dummy);
    cudaDeviceSynchronize();

    // Sweep through sizes
    for (size_t size = min_size; size <= max_size; size += step_size) {
        cudaMemset((void*)d_data, 0, size);

        cudaEvent_t start, stop;
        cudaEventCreate(&start);
        cudaEventCreate(&stop);

        dim3 blockDim(256);
        size_t num_elements = size / sizeof(uint32_t);
        dim3 gridDim((num_elements + blockDim.x - 1) / blockDim.x);

        float total_time = 0.0f;
        for (int rep = 0; rep < repetitions; rep++) {
            cudaEventRecord(start);
            l2_cache_test_kernel<<<gridDim, blockDim>>>(d_data, size, stride, d_dummy);
            cudaEventRecord(stop);
            cudaEventSynchronize(stop);

            float milliseconds = 0.0f;
            cudaEventElapsedTime(&milliseconds, start, stop);
            total_time += milliseconds;

            cudaEventDestroy(start);
            cudaEventDestroy(stop);
        }

        float avg_time = total_time / repetitions;
        times[(size - min_size) / step_size] = avg_time;
    }

    // Find the cliff point
    // Look for the point where time increases significantly
    float baseline = times[0];
    int cliff_index = 0;
    for (int i = 1; i < (max_size - min_size) / step_size; i++) {
        if (times[i] > baseline * 1.5f) { // 50% increase threshold
            cliff_index = i - 1;
            break;
        }
    }

    size_t l2_size_bytes = min_size + cliff_index * step_size;
    size_t l2_size_mb = l2_size_bytes / MB;

    printf("l2_cache_size_mb: %lu\n", l2_size_mb);

    cudaFree((void*)d_data);
    cudaFree(d_dummy);
    free(times);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

// L2 Cache Size Detection via Working-Set Sweep
// Strategy: Sweep array sizes and detect the cliff where latency increases

__global__ void measure_access_time(volatile uint32_t* data, size_t size, uint64_t* cycles_out) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t idx = 0;
    asm volatile("" : : : "memory");

    volatile uint64_t start = clock64();
    #pragma unroll 1
    for (uint64_t i = 0; i < 500000; i++) {
        idx = data[idx % (size / sizeof(uint32_t))];
        if (idx >= size / sizeof(uint32_t)) idx = 0;
    }
    volatile uint64_t end = clock64();

    asm volatile("" : : : "memory");
    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    *cycles_out = (end - start) / 500000;
}

int main() {
    const size_t min_size = 1 * 1024 * 1024;  // 1 MB
    const size_t max_size = 100 * 1024 * 1024; // 100 MB
    const size_t step_size = 1 * 1024 * 1024;  // 1 MB steps

    uint64_t* h_results = (uint64_t*)malloc(100 * sizeof(uint64_t));
    uint64_t* d_result;
    cudaMalloc((void**)&d_result, sizeof(uint64_t));

    // Test array sizes from 1MB to 100MB
    size_t test_sizes[] = {1, 2, 4, 8, 12, 16, 20, 24, 28, 32, 36, 40, 44, 48, 52, 56, 60, 64, 72, 80, 90, 100};
    int num_sizes = sizeof(test_sizes) / sizeof(test_sizes[0]);

    for (int i = 0; i < num_sizes; i++) {
        size_t size_mb = test_sizes[i];
        size_t array_size = (size_mb * 1024 * 1024) / sizeof(uint32_t);

        volatile uint32_t* d_data;
        cudaMalloc((void**)&d_data, array_size * sizeof(uint32_t));

        // Initialize data - create pointer-chasing pattern
        uint32_t* h_data = (uint32_t*)malloc(array_size * sizeof(uint32_t));
        for (size_t j = 0; j < array_size; j++) {
            h_data[j] = (j + 1) % array_size;
        }
        cudaMemcpy((void*)d_data, h_data, array_size * sizeof(uint32_t), cudaMemcpyHostToDevice);
        free(h_data);

        measure_access_time<<<1,1>>>(d_data, array_size * sizeof(uint32_t), d_result);
        cudaDeviceSynchronize();

        cudaMemcpy(&h_results[i], d_result, sizeof(uint64_t), cudaMemcpyDeviceToHost);

        cudaFree((void*)d_data);
    }

    // Find the cliff: largest array size where latency is still in the low range
    uint64_t baseline = h_results[0];
    int cliff_index = 0;
    for (int i = 1; i < num_sizes; i++) {
        if (h_results[i] > baseline * 1.5) {  // 50% increase indicates cliff
            cliff_index = i - 1;
            break;
        }
        cliff_index = i;
    }

    float l2_size_mb = (float)test_sizes[cliff_index];
    printf("l2_cache_size_mb: %.0f\n", l2_size_mb);

    free(h_results);
    cudaFree(d_result);
    return 0;
}
